// @hoge1e3/immer-path-ref
import {produce} from "immer";
import { Ref } from "@hoge1e3/ref";

type PathComponent<T, N> = 
  ((t: T) => N) | keyof T;
export interface PathRef<T> 
  extends Ref<T>{
  join<N>(path:((t: T) => N)):PathRef<N>;
  
} 
export function create<T, K extends keyof T>(
  r: Ref<T>,
  path: K
): T[K];
export function create<T, N>(
  r: Ref<T>,
  path: (t: T) => N
): N;
export function create<T, K extends keyof T, N>(
  r: Ref<T>,
  path: K | ((t: T) => N)
): T[K] | N {
  if (typeof path === "function") {
    return path(r.value);
  } else {
    return r.value[path];
  }
}